/bin/bash -lc "python - <<'PY'
import json,re
with open('kg/graph.json','r',encoding='utf-8') as f:
    data=json.load(f)
paths=[]
pat=re.compile(r'(best|热销|销量|转化率|成交金额|product-data|商品)',re.I)

def walk(x):
    if isinstance(x,dict):
        for k,v in x.items():
            if k in ('path','file','source','filepath') and isinstance(v,str) and pat.search(v):
                paths.append(v)
            walk(v)
    elif isinstance(x,list):
        for v in x: walk(v)
    elif isinstance(x,str):
        if '/' in x and pat.search(x):
            paths.append(x)
walk(data)
for p in sorted(set(paths))[:200]:
    print(p)
print('count', len(set(paths)))
PY"

